import{_ as o,o as i,c as a,ag as d}from"./chunks/framework.DTiDeF2Q.js";const _=JSON.parse('{"title":"นามแฝง Chmod | Dotfiles (TH)","titleTemplate":":title","description":"คำสั่งสิทธิ์แบบสั้น ภาพรวมสำหรับ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","frontmatter":{"title":"นามแฝง Chmod | Dotfiles","description":"คำสั่งสิทธิ์แบบสั้น ภาพรวมสำหรับ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","lang":"th-TH","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"นามแฝง Chmod | Dotfiles preview","canonical":"/th/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"นามแฝง Chmod","pageType":"docs","schemaType":"WebPage","permalink":"/th/aliases/chmod/"},"headers":[],"relativePath":"th/aliases/chmod/index.md","filePath":"th/aliases/chmod/index.md","lastUpdated":1773010926000}'),c={name:"th/aliases/chmod/index.md"};function l(t,e,s,h,n,r){return i(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="นามแฝง-chmod" tabindex="-1">นามแฝง Chmod <a class="header-anchor" href="#นามแฝง-chmod" aria-label="Permalink to &quot;นามแฝง Chmod&quot;">​</a></h1><p>คำสั่งสิทธิ์แบบสั้น</p><p>หน้านี้แนะนำกลุ่มนามแฝงหนึ่งกลุ่มและทางลัดคำสั่งทั่วไป อ่านหน้านี้ก่อนเพื่อทำความเข้าใจแบบแผนการตั้งชื่อ อินพุตที่คาดหวัง และรูปแบบการดำเนินการที่ปลอดภัย จากนั้นเปิดภาคผนวกอ้างอิงเพื่อดูรายการคำสั่งทั้งหมดและไวยากรณ์ที่แน่นอน นามแฝงเหล่านี้ลดการพิมพ์ซ้ำและรักษาพฤติกรรมเวิร์กโฟลว์ที่สม่ำเสมอบน macOS, Linux และ WSL</p><h2 id="เมื่อใดควรใช้" tabindex="-1">เมื่อใดควรใช้ <a class="header-anchor" href="#เมื่อใดควรใช้" aria-label="Permalink to &quot;เมื่อใดควรใช้&quot;">​</a></h2><p>ใช้หน้านี้ก่อนการทำงานเชลล์ประจำวันเมื่อคุณต้องการรูปแบบคำสั่งที่คาดเดาได้</p><h2 id="สิ่งที่รวมอยู่" tabindex="-1">สิ่งที่รวมอยู่ <a class="header-anchor" href="#สิ่งที่รวมอยู่" aria-label="Permalink to &quot;สิ่งที่รวมอยู่&quot;">​</a></h2><ul><li>นามแฝง: 17</li><li>ฟังก์ชันตัวช่วย: 0</li><li>ไฟล์ต้นฉบับ: 1</li></ul><h2 id="ตัวอย่างสั้น" tabindex="-1">ตัวอย่างสั้น <a class="header-anchor" href="#ตัวอย่างสั้น" aria-label="Permalink to &quot;ตัวอย่างสั้น&quot;">​</a></h2><ul><li><code>chmod_000</code> → <code>change_permission 000</code></li><li><code>chmod_1755</code> → <code>&#39;change_permission 1755&#39; # Sticky bit + 755</code></li><li><code>chmod_2755</code> → <code>&#39;change_permission 2755&#39; # Setgid + 755</code></li><li><code>chmod_400</code> → <code>&#39;change_permission 400&#39; # อ่านอย่างเดียวสำหรับเจ้าของ</code></li><li><code>chmod_444</code> → <code>&#39;change_permission 444&#39; # อ่านอย่างเดียวสำหรับทุกคน</code></li><li><code>chmod_4755</code> → <code>&#39;change_permission 4755&#39; # Setuid + 755</code></li><li><code>chmod_600</code> → <code>&#39;change_permission 600&#39; # อ่าน/เขียนสำหรับเจ้าของ</code></li><li><code>chmod_644</code> → <code>&#39;change_permission 644&#39; # อ่าน/เขียนสำหรับเจ้าของ อ่านสำหรับคนอื่น</code></li><li><code>chmod_664</code> → <code>&#39;change_permission 664&#39; # อ่าน/เขียนสำหรับเจ้าของและกลุ่ม อ่านสำหรับคนอื่น</code></li><li><code>chmod_666</code> → <code>&#39;change_permission 666&#39; # อ่าน/เขียนสำหรับทุกคน</code></li><li><code>chmod_700</code> → <code>&#39;change_permission 700&#39; # สิทธิ์เต็มสำหรับเจ้าของเท่านั้น</code></li><li><code>chmod_744</code> → <code>&#39;change_permission 744&#39; # สิทธิ์เต็มสำหรับเจ้าของ อ่านสำหรับคนอื่น</code></li></ul><h2 id="ขั้นตอนถัดไป" tabindex="-1">ขั้นตอนถัดไป <a class="header-anchor" href="#ขั้นตอนถัดไป" aria-label="Permalink to &quot;ขั้นตอนถัดไป&quot;">​</a></h2><p>เปิดรายการทั้งหมด:</p>',11)])])}const p=o(c,[["render",l]]);export{_ as __pageData,p as default};
